317	/// An enum that reports whether a `Parker::park_timeout` or
318	/// `Parker::park_deadline` returned because another thread called `unpark` or
319	/// because of a timeout.
320	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
321	pub enum UnparkReason {
322	    /// The park method returned due to a call to `unpark`.
323	    Unparked,
324	
325	    /// The park method returned due to a timeout.
326	    Timeout,
327	}
328	
329	const EMPTY: usize = 0;
330	const PARKED: usize = 1;
331	const NOTIFIED: usize = 2;
332	
333	struct Inner {
334	    state: AtomicUsize,
335	    lock: Mutex<()>,
336	    cvar: Condvar,
337	}
338	
339	impl Inner {
340	    fn park(&self, deadline: Option<Instant>) -> UnparkReason {
341	        // If we were previously notified then we consume this notification and return quickly.
342	        if self
343	            .state
344	            .compare_exchange(NOTIFIED, EMPTY, SeqCst, SeqCst)
345	            .is_ok()
346	        {
347	            return UnparkReason::Unparked;
348	        }
349	
350	        // If the timeout is zero, then there is no need to actually block.
351	        if let Some(deadline) = deadline {
352	            if deadline <= Instant::now() {
353	                return UnparkReason::Timeout;
354	            }
355	        }
356	
357	        // Otherwise we need to coordinate going to sleep.
358	        let mut m = self.lock.lock().unwrap();
359	
360	        match self.state.compare_exchange(EMPTY, PARKED, SeqCst, SeqCst) {
361	            Ok(_) => {}
362	            // Consume this notification to avoid spurious wakeups in the next park.
363	            Err(NOTIFIED) => {
364	                // We must read `state` here, even though we know it will be `NOTIFIED`. This is
365	                // because `unpark` may have been called again since we read `NOTIFIED` in the
366	                // `compare_exchange` above. We must perform an acquire operation that synchronizes
367	                // with that `unpark` to observe any writes it made before the call to `unpark`. To
368	                // do that we must read from the write it made to `state`.
369	                let old = self.state.swap(EMPTY, SeqCst);
370	                assert_eq!(old, NOTIFIED, "park state changed unexpectedly");
371	                return UnparkReason::Unparked;
372	            }
373	            Err(n) => panic!("inconsistent park_timeout state: {}", n),
374	        }
375	
376	        loop {
377	            // Block the current thread on the conditional variable.
378	            m = match deadline {
379	                None => self.cvar.wait(m).unwrap(),
380	                Some(deadline) => {
381	                    let now = Instant::now();
382	                    if now < deadline {
383	                        // We could check for a timeout here, in the return value of wait_timeout,
384	                        // but in the case that a timeout and an unpark arrive simultaneously, we
385	                        // prefer to report the former.
386	                        self.cvar.wait_timeout(m, deadline - now).unwrap().0
387	                    } else {
388	                        // We've timed out; swap out the state back to empty on our way out
389	                        return match self.state.swap(EMPTY, SeqCst) {
390	                            NOTIFIED => UnparkReason::Unparked, // got a notification
391	                            PARKED => UnparkReason::Timeout,    // no notification
392	                            n => panic!("inconsistent park_timeout state: {}", n),
393	                        };
394	                    }
395	                }
396	            };
397	
398	            if self
399	                .state
400	                .compare_exchange(NOTIFIED, EMPTY, SeqCst, SeqCst)
401	                .is_ok()
402	            {
403	                // got a notification
404	                return UnparkReason::Unparked;
405	            }
406	
407	            // Spurious wakeup, go back to sleep. Alternatively, if we timed out, it will be caught
408	            // in the branch above, when we discover the deadline is in the past
409	        }
410	    }
411	
412	    pub(crate) fn unpark(&self) {
413	        // To ensure the unparked thread will observe any writes we made before this call, we must
414	        // perform a release operation that `park` can synchronize with. To do that we must write
415	        // `NOTIFIED` even if `state` is already `NOTIFIED`. That is why this must be a swap rather
416	        // than a compare-and-swap that returns if it reads `NOTIFIED` on failure.
417	        match self.state.swap(NOTIFIED, SeqCst) {
418	            EMPTY => return,    // no one was waiting
419	            NOTIFIED => return, // already unparked
420	            PARKED => {}        // gotta go wake someone up
421	            _ => panic!("inconsistent state in unpark"),
422	        }
423	
424	        // There is a period between when the parked thread sets `state` to `PARKED` (or last
425	        // checked `state` in the case of a spurious wakeup) and when it actually waits on `cvar`.
426	        // If we were to notify during this period it would be ignored and then when the parked
427	        // thread went to sleep it would never wake up. Fortunately, it has `lock` locked at this
428	        // stage so we can acquire `lock` to wait until it is ready to receive the notification.
429	        //
430	        // Releasing `lock` before the call to `notify_one` means that when the parked thread wakes
431	        // it doesn't get woken only to have to wait for us to release `lock`.
432	        drop(self.lock.lock().unwrap());
433	        self.cvar.notify_one();
434	    }
435	}
